import type React from "react";

import { CARD_CLASSES } from "./constants";

interface BackCardContentProps {
  name: string;
  personalityPhrase?: string;
  userBio?: string;
  accountNumber: string | number;
  memberSince: string | number;
  isStatic?: boolean;
}

export const BackCardContent: React.FC<BackCardContentProps> = ({
  name,
  personalityPhrase,
  userBio,
  isStatic = false,
}) => {
  return (
    <div className="flex w-full flex-col gap-4">
      <div className={CARD_CLASSES.INFO_BOX_BACK}>
        <div
          className={
            isStatic
              ? "mb-2 font-serif text-2xl font-normal text-white"
              : "mb-0 font-serif text-2xl font-normal text-white"
          }
        >
          {name}
        </div>
        <div
          className={
            isStatic
              ? "mb-4 text-sm font-light text-white/80 italic"
              : "mb-2 text-sm font-light text-white/80 italic"
          }
        >
          {personalityPhrase}
        </div>
        <p className="scrollbar-faint pointer-events-auto max-h-60 overflow-y-auto overscroll-contain text-sm text-white/80">
          {userBio}
        </p>
      </div>
    </div>
  );
};

interface BackCardFooterProps {
  accountNumber: string | number;
  memberSince: string | number;
  isStatic?: boolean;
}

export const BackCardFooter: React.FC<BackCardFooterProps> = ({
  accountNumber,
  memberSince,
  isStatic = false,
}) => {
  return (
    <div className={CARD_CLASSES.FOOTER_BOX}>
      <div className="flex flex-col gap-1">
        <span
          className={
            isStatic
              ? "text-xs text-white/50 font-mono! uppercase"
              : "text-xs text-white/50 font-mono uppercase"
          }
        >
          Member Since
        </span>
        <span className="text-sm font-medium text-white/80 font-mono uppercase">
          {memberSince}
        </span>
      </div>
      <div className="flex flex-col items-end gap-1">
        <span className="text-xs text-white/50 font-mono uppercase">
          User ID
        </span>
        <span
          className={
            isStatic
              ? "text-sm font-medium text-white/80 font-mono uppercase"
              : "text-sm font-medium text-white/80"
          }
        >
          {accountNumber}
        </span>
      </div>
    </div>
  );
};

// Image paths used across HoloCard components
export const CARD_IMAGES = {
  // Plain GAIA icon (white-on-transparent PNG, no embedded wordmark).
  // The wordmark is rendered as live HTML text in LogoHeader so we avoid the
  // html-to-image bug that paints WebPs' alpha-0 RGB pixels as opaque.
  LOGO_WHITE: "/brand/gaia_logo.png",
  EXPERIENCE_LOGO: "/brand/experience_logo_white.png",
} as const;

// Logo dimensions
export const LOGO_SIZES = {
  FRONT: {
    width: 100,
    height: 30,
  },
  BACK: {
    width: 80,
    height: 24,
  },
} as const;

// Position calculation constants
export const POSITION_CALC = {
  DAMPING_FACTOR: 1.5, // Used to dampen the background position offset
} as const;

// Common CSS class patterns
export const CARD_CLASSES = {
  OVERLAY: "pointer-events-none absolute inset-0 z-3",
  CONTENT_WRAPPER:
    "pointer-events-none absolute z-2 flex h-full w-full flex-col items-start justify-end p-9 text-white transition",
  CONTENT_WRAPPER_BACK:
    "pointer-events-none absolute z-2 flex h-full w-full flex-col items-start justify-between p-9 text-white",
  LOGO_BADGE: "font-serif text-xl font-light text-white",
  HOUSE_BADGE:
    "rounded-full bg-white/20 p-1 px-4 font-serif text-xl font-light text-white/70 backdrop-blur-md",
  HOUSE_BADGE_BACK:
    "rounded-full bg-white/20 p-1 px-3 font-serif text-xl font-light text-white/70 backdrop-blur-md",
  INFO_BOX:
    "relative flex w-full flex-col gap-1 overflow-hidden rounded-2xl bg-black/20 p-3 backdrop-blur-md",
  INFO_BOX_BACK:
    "relative overflow-hidden rounded-2xl bg-black/20 p-4 backdrop-blur-md",
  FOOTER_BOX:
    "flex w-full items-center justify-between rounded-xl bg-black/20 p-3 backdrop-blur-md",
} as const;

