54	
55	  const handleCardClick = () => {
56	    if (!forceSide) {
57	      setIsFlipped((prev) => !prev);
58	    }
59	  };
60	
61	  const handleOnMouseMove = (event: React.MouseEvent<HTMLDivElement>) => {
62	    setAnimated(false);
63	    setHover(true);
