1	/**
2	 * Inline holo-card reveal shown above the chat stream. Four-state machine:
3	 *   idle (giftbox) → vibrating (anticipation) → bursting (scale-up + fade)
4	 *   → revealed (editable card with confetti)
5	 *
6	 * On hover the giftbox scales and lifts slightly, signalling it's interactive.
7	 * The "bursting" step double-buffers the visuals: the giftbox scales and fades
8	 * out while the card scales in underneath, so the transition reads as the box
9	 * opening rather than disappearing flatly.
10	 */
11	
12	"use client";
13	
14	import confetti from "canvas-confetti";
15	import { AnimatePresence } from "motion/react";
16	import * as m from "motion/react-m";
17	import Image from "next/image";
18	import { useEffect, useRef, useState } from "react";
19	
20	import { HoloCardEditor } from "@/components/ui/holo-card/HoloCardEditor";
21	import type { HoloCardDisplayData } from "@/components/ui/holo-card/types";
22	import { HOLO_CARD_HEIGHT, HOLO_CARD_WIDTH } from "../../constants";
23	import type { PersonalizationData } from "../../types/websocket";
24	
25	interface HoloCardRevealProps {
26	  personalizationData: PersonalizationData;
27	}
28	
29	type RevealState = "idle" | "vibrating" | "bursting" | "revealed";
30	
31	// Container is sized to the holo card so the giftbox and the revealed card
32	// share an anchor — no layout jump when the state flips.
33	const GIFTBOX_SRC = "/images/onboarding/giftbox.png";
34	
35	export function HoloCardReveal({ personalizationData }: HoloCardRevealProps) {
36	  const [revealState, setRevealState] = useState<RevealState>("idle");
37	  const cardWrapRef = useRef<HTMLDivElement>(null);
38	
39	  // Choreography on reveal:
40	  //   t=0    card mounts, springs in from scale 0.7 (overlapping the
41	  //          giftbox burst so there is no visual gap)
42	  //   t=0    scroll kicks off immediately so the card grows into view —
43	  //          starting the scroll here means it settles before the spring
44	  //          finishes, removing the "jump" the user felt
45	  //   t=420  fire confetti from the card's actual on-screen centre
46	  // Confetti waits until the scroll has settled so the particles spawn
47	  // at the card's final position, not its stale pre-scroll origin.
48	  useEffect(() => {
49	    if (revealState !== "revealed") return;
50	    cardWrapRef.current?.scrollIntoView({
51	      behavior: "smooth",
52	      block: "center",
53	    });
54	    const confettiTimer = window.setTimeout(() => {
55	      const node = cardWrapRef.current;
56	      const origin = node
57	        ? (() => {
58	            const rect = node.getBoundingClientRect();
59	            return {
60	              x: (rect.left + rect.width / 2) / window.innerWidth,
61	              y: (rect.top + rect.height / 2) / window.innerHeight,
62	            };
63	          })()
64	        : { x: 0.5, y: 0.55 };
65	      confetti({
66	        particleCount: 160,
67	        spread: 80,
68	        startVelocity: 45,
69	        origin,
70	      });
71	    }, 420);
72	    return () => {
73	      window.clearTimeout(confettiTimer);
74	    };
75	  }, [revealState]);
76	
77	  const holoCardData: HoloCardDisplayData = {
78	    house: personalizationData.house ?? "bluehaven",
79	    name: personalizationData.name ?? "User",
80	    personality_phrase:
81	      personalizationData.personality_phrase ?? "Curious Adventurer",
82	    user_bio:
83	      personalizationData.user_bio ??
84	      "A passionate individual exploring new possibilities and making an impact.",
85	    account_number: personalizationData.account_number
86	      ? `#${personalizationData.account_number}`
87	      : "#00000",
88	    member_since:
89	      personalizationData.member_since ??
90	      new Date().toLocaleDateString("en-US", {
91	        month: "short",
92	        day: "numeric",
93	        year: "numeric",
94	      }),
95	    overlay_color: personalizationData.overlay_color ?? "rgba(0,0,0,0)",
96	    overlay_opacity: personalizationData.overlay_opacity ?? 40,
97	    holo_card_id: personalizationData.holo_card_id,
98	  };
99	
100	  const handleGiftboxClick = () => {
101	    if (revealState !== "idle") return;
102	    setRevealState("vibrating");
103	  };
104	
105	  const handleVibrationComplete = () => {
106	    setRevealState("bursting");
107	  };
108	
109	  const handleBurstComplete = () => {
110	    setRevealState("revealed");
111	  };
112	
113	  return (
114	    <m.div
115	      className="flex flex-col items-center py-2"
116	      initial={{ opacity: 0, y: 8 }}
117	      animate={{ opacity: 1, y: 0 }}
118	      transition={{ duration: 0.35 }}
119	    >
120	      <div
121	        className="relative flex items-center justify-center"
122	        style={{
123	          width: HOLO_CARD_WIDTH,
124	          minHeight:
125	            revealState === "revealed" || revealState === "bursting"
126	              ? HOLO_CARD_HEIGHT
127	              : "auto",
128	        }}
129	      >
130	        <AnimatePresence>
131	          {revealState !== "revealed" && (
132	            <m.button
133	              key="giftbox"
134	              type="button"
135	              aria-label="Tap to reveal your personalized GAIA card"
136	              onClick={handleGiftboxClick}
137	              disabled={revealState !== "idle"}
138	              className={
139	                revealState === "bursting"
140	                  ? "pointer-events-none absolute inset-0 flex cursor-pointer items-center justify-center bg-transparent outline-none"
141	                  : "group relative flex cursor-pointer items-center justify-center bg-transparent outline-none"
142	              }
143	              style={{ perspective: 1000 }}
144	              exit={{ opacity: 0, transition: { duration: 0.15 } }}
145	              initial={{ opacity: 0, scale: 0.9 }}
146	              animate={
147	                revealState === "vibrating"
148	                  ? {
149	                      opacity: 1,
150	                      scale: [1, 1.04, 1.04, 1, 1, 1, 1, 1],
151	                      rotate: [0, -8, 8, -10, 10, -6, 6, -3, 3, 0],
152	                      x: [0, -4, 4, -6, 6, -4, 4, -2, 2, 0],
153	                    }
154	                  : revealState === "bursting"
155	                    ? {
156	                        opacity: [1, 1, 0],
157	                        scale: [1, 1.3, 1.6],
158	                        rotate: 0,
159	                        x: 0,
160	                      }
161	                    : { opacity: 1, scale: 1, rotate: 0, x: 0 }
162	              }
163	              whileHover={
164	                revealState === "idle" ? { scale: 1.06, y: -6 } : undefined
165	              }
166	              whileTap={revealState === "idle" ? { scale: 0.97 } : undefined}
167	              transition={
168	                revealState === "vibrating"
169	                  ? { duration: 0.7, ease: "easeInOut" }
170	                  : revealState === "bursting"
171	                    ? { duration: 0.45, ease: "easeOut" }
172	                    : { type: "spring", stiffness: 320, damping: 22 }
173	              }
174	              onAnimationComplete={
175	                revealState === "vibrating"
176	                  ? handleVibrationComplete
177	                  : revealState === "bursting"
178	                    ? handleBurstComplete
179	                    : undefined
180	              }
181	            >
182	              <m.div
183	                className="relative flex flex-col items-center"
184	                style={{ width: HOLO_CARD_WIDTH }}
185	                animate={revealState === "idle" ? { y: [0, -6, 0] } : { y: 0 }}
186	                transition={
187	                  revealState === "idle"
188	                    ? { duration: 3, repeat: Infinity, ease: "easeInOut" }
189	                    : undefined
190	                }
191	              >
192	                <Image
193	                  src={GIFTBOX_SRC}
194	                  alt=""
195	                  width={1360}
196	                  height={952}
197	                  priority
198	                  className="h-auto w-[240px] select-none"
199	                  draggable={false}
200	                />
201	                {revealState === "idle" && (
202	                  <m.p
203	                    className="mt-4 text-sm text-white/80"
204	                    initial={{ opacity: 0 }}
205	                    animate={{ opacity: [0.5, 1, 0.5] }}
206	                    transition={{ duration: 2.4, repeat: Infinity }}
207	                  >
208	                    Click to open
209	                  </m.p>
210	                )}
211	              </m.div>
212	            </m.button>
213	          )}
214	
215	          {(revealState === "bursting" || revealState === "revealed") && (
216	            <m.div
217	              key="card"
218	              ref={cardWrapRef}
219	              className={
220	                revealState === "bursting"
221	                  ? "absolute inset-0 flex flex-col items-center gap-4"
222	                  : "flex flex-col items-center gap-4"
223	              }
224	              role="img"
225	              aria-label="Your personalized GAIA member card"
226	              initial={{ opacity: 0, scale: 0.7 }}
227	              animate={{ opacity: 1, scale: 1 }}
228	              transition={{
229	                type: "spring",
230	                stiffness: 180,
231	                damping: 22,
232	                mass: 0.9,
233	              }}
234	            >
235	              <HoloCardEditor
236	                initialData={holoCardData}
237	                height={HOLO_CARD_HEIGHT}
238	                width={HOLO_CARD_WIDTH}
239	              />
240	              <p className="text-sm text-zinc-400">
241	                Click to flip your personalised profile card
242	              </p>
243	            </m.div>
244	          )}
245	        </AnimatePresence>
246	      </div>
247	    </m.div>
248	  );
249	}
